int convert_to_words(char *s,char words[][20])
{
   int nword=0;int j=0;
   while(*s)
   {
      if(*s==' '||*s=='\t')
      {
           words[nword][j]=0;
           nword++; j=0;
      }
      else
      {
           words[nword][j++]=*s;
      }
      s++;
    }
    words[nword][j]=0;
    nword++;
    return nword;
