void reverse_words(char words[][20],int nwords)
{
   int i,j;
   for(i=0,j=nwords-1;i<j;i++,j--)
   {
       char temp[20];
       strcpy(temp,words[i]);
       strcpy(words[i],words[j]);
       strcpy(words[j],temp);
    }
}
