void remove_duplicates(char words[][20],int nwords)
{
   int i,j;
   char tempstr[100];
   for(i=0;i<nwords;i++)
   {
       char temp[20];
       strcpy(temp,words[i]);
       for(j=i+1;j<nwords;j++)
       {
          if(strcmp(temp,words[j])==0)
          {
             pack_string(words,tempstr,j,nwords);
             nwords = convert_to_words(tempstr,words);
           }
        }

    }
}
