      printf("%s ",words[i]);
}
void pack_string(char words[][20],char *str,int omit_this,int num_words)
{
    int i;
    strcpy(str,"");
    for(i=0;i<num_words;i++)
    {
        if(i!=omit_this)
        {
            strcat(str,words[i]);
            strcat(str," ");
        }
     }
}

