void read_file(FILE *fptr,FILE *fptrout1,FILE *fptrout2)
{
    int i=1;
    int n;
    while(!feof(fptr))
    {
        fread(&n,sizeof(n),1,fptr);//fread used for binary files
        if(i%2==0)
        {
          fwrite(&n,sizeof(n),1,fptrout2);
        }
        else
          {
             fwrite(&n,sizeof(n),1,fptrout1 );
          }
       i++;
    }
    fclose(fptr);
    fclose(fptrout1);
    fclose(fptrout2);
}

