void primeFactors(int n)
{
    /* Print the number of 2s that divide n*/
    while (n%2 == 0)
    {
        printf("%d ", 2);
        n = n/2;
    }

    /* n must be odd at this point.  So we can skip one element*/
    for (int i = 3; i <= sqrt(n); i = i+2)
    {
        /* remove all i-s from the number */
        while (n%i == 0)
        {
            printf("%d ", i);
            n = n/i;
        }
    }


    if (n > 2)
        printf ("%d ", n);
}

