   int swapped= 1;
   for(i=0;i<n-1  && swapped;i++)
     {
        swapped = 0;
        for(j=0;j<n-i-1 ; j++)
             if(arr[j+1]<arr[j])
                 {
                    int temp=arr[j];
                    arr[j] = arr[j+1];
                    arr[j+1] = temp;
                    swapped = 1;
                  }
     }
}

