         return i;
   return -1;
}

int binary_search(int *arr,int size,int n)
{
    int start = 0;int end=size-1;
    int mid = (end+start)/2;
    while( end>=start)
        {
           if(arr[mid]>n)
              end = mid-1;
           else if (arr[mid]<n)
              start = mid+1;
           else
             return mid;
           mid = (end+start)/2;
         }

    return -1;
}

#include<stdio.h>
int binary_search_recursive(int *arr,int start,int end,int num)
{
    if(start>end)
      return -1;
    int mid = (start+end)/2;
    if(arr[mid]==num)
      return mid;
    else if(arr[mid]>num)
      return binary_search_recursive(arr,start,mid-1,num);
    else
      return binary_search_recursive(arr,mid+1,end,num);
 }
void bubble_sort(int *arr,int n)
{
   int i,j;
   int swapped= 1;
   for(i=0;i<n-1  && swapped;i++)//n-1 passes
     {
        swapped = 0;
        for(j=0;j<n-i-1 ; j++)
             if(arr[j+1]<arr[j])
                 {
                    int temp=arr[j];
                    arr[j] = arr[j+1];
                    arr[j+1] = temp;
                    swapped = 1;
                  }
     }
}
