#define NUM_TERMS 30
#define PI 22.0/7
long int factorial(int num)
{
   if(num==0)
      return 1;
   else
      return num*factorial(num-1);
}
float cosine(float x)
{

     float sum =1.0;
     int i;
     int sign = -1;
     x = x * PI/180;/*convert to radians*/
     for(i=2;i<NUM_TERMS;i+=2)
      {
         float term = pow(x,i)/factorial(i);
         sum+=sign*term;
         sign *=-1;
       }
     return sum;
}

