char *myitoa(int num)
{
   int nd = num_digits(num);
   int i,j=0;
   char *temp = malloc(30);
   char *t2 = temp;
   for(i=nd;i>=0;i--)
   {
       int ipower = pow(10,i);
       int digit = num/ipower;
       char ch;
       num = num %ipower;
       ch = digit+48;/*code of 0 is 48,1 is 49 etc*/
       *temp++=ch;
    }
    *temp=0;
    return t2;
}
int num_digits(int n)
{
   int d = 0;
   while(n)
    {
      n/=10;
      d++;
    }
    return d-1;
}
